# Payments API вҖ” Error Handling Refactor

## Phase 3: Global Error Handling Strategy

---

## Part 1: Design Overview

### Core Principle

Every error response in this API must conform to **RFC 9457 Problem Details** (`application/problem+json`). No exceptions. No fallback to custom formats. This was decided in ADR-003 and is an active HIGH constraint.

The design has three layers:

```
Request
  в”Ӯ
  в–ј
Route Handler
  в”Ӯ  throws typed AppError subclass
  в–ј
Global Error Middleware          вҶҗ single place where responses are written
  в”Ӯ  maps error type вҶ’ Problem Details
  в–ј
HTTP Response (application/problem+json)
```

All error-producing code **throws**. Nothing writes a response directly except the global error middleware. This eliminates the "some routes use res.json({error:...}), some use next(err)" inconsistency that typically accumulates across phases.

---

## Part 2: Error Type Hierarchy

```typescript
// src/errors/AppError.ts

/**
 * Base class for all application errors.
 * Every subclass maps to one entry in the error type registry
 * at https://api.payments.example/errors/
 */
export abstract class AppError extends Error {
  abstract readonly typeSlug: string;       // e.g. "authentication-required"
  abstract readonly defaultTitle: string;   // e.g. "Authentication Required"
  abstract readonly httpStatus: number;     // e.g. 401

  constructor(
    public readonly detail: string,
    public readonly extensions: Record<string, unknown> = {}
  ) {
    super(detail);
    this.name = this.constructor.name;
    // Preserve prototype chain across transpilation
    Object.setPrototypeOf(this, new.target.prototype);
  }
}

// в”Җв”Җв”Җ Authentication Errors (401 vs 403 вҖ” see Section 4) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

/**
 * 401 Unauthenticated вҖ” no valid credentials were presented.
 * The client MUST authenticate before retrying.
 * WWW-Authenticate header is added by the error middleware.
 */
export class AuthenticationRequiredError extends AppError {
  readonly typeSlug = "authentication-required";
  readonly defaultTitle = "Authentication Required";
  readonly httpStatus = 401;
}

/**
 * 401 вҖ” credentials were presented but are invalid/expired.
 * Distinct from AuthenticationRequiredError for clearer client messaging,
 * but still 401 because the request was not authenticated.
 */
export class InvalidTokenError extends AppError {
  readonly typeSlug = "invalid-token";
  readonly defaultTitle = "Invalid or Expired Token";
  readonly httpStatus = 401;
}

/**
 * 403 Forbidden вҖ” identity is established but lacks permission.
 * The client should NOT retry with the same credentials.
 */
export class PermissionDeniedError extends AppError {
  readonly typeSlug = "permission-denied";
  readonly defaultTitle = "Permission Denied";
  readonly httpStatus = 403;
}

// в”Җв”Җв”Җ Rate Limiting Errors в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

/**
 * 429 Too Many Requests.
 * MUST carry retryAfterSeconds вҖ” enforced by constructor signature.
 * The error middleware uses this to set Retry-After (contractual obligation).
 */
export class RateLimitError extends AppError {
  readonly typeSlug = "rate-limited";
  readonly defaultTitle = "Rate Limit Exceeded";
  readonly httpStatus = 429;

  constructor(
    detail: string,
    public readonly retryAfterSeconds: number,
    public readonly limitMax: number,
    public readonly limitReset: number   // Unix timestamp
  ) {
    super(detail, {
      retry_after: retryAfterSeconds,
    });
    if (!Number.isFinite(retryAfterSeconds) || retryAfterSeconds < 0) {
      throw new TypeError("RateLimitError requires a non-negative retryAfterSeconds");
    }
  }
}

// в”Җв”Җв”Җ Validation Errors в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

export interface FieldError {
  field: string;
  message: string;
  received?: unknown;
}

export class ValidationError extends AppError {
  readonly typeSlug = "validation-failed";
  readonly defaultTitle = "Validation Failed";
  readonly httpStatus = 422;

  constructor(
    detail: string,
    public readonly fieldErrors: FieldError[]
  ) {
    super(detail, { validation_errors: fieldErrors });
  }
}

// в”Җв”Җв”Җ Payment Domain Errors в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

export class InsufficientFundsError extends AppError {
  readonly typeSlug = "insufficient-funds";
  readonly defaultTitle = "Insufficient Funds";
  readonly httpStatus = 402;
}

export class CardDeclinedError extends AppError {
  readonly typeSlug = "card-declined";
  readonly defaultTitle = "Card Declined";
  readonly httpStatus = 402;
}

export class InvalidPaymentMethodError extends AppError {
  readonly typeSlug = "invalid-payment-method";
  readonly defaultTitle = "Invalid Payment Method";
  readonly httpStatus = 400;
}

export class IdempotencyConflictError extends AppError {
  readonly typeSlug = "idempotency-conflict";
  readonly defaultTitle = "Idempotency Key Conflict";
  readonly httpStatus = 409;
}

export class GatewayError extends AppError {
  readonly typeSlug = "gateway-error";
  readonly defaultTitle = "Payment Gateway Error";
  readonly httpStatus = 502;
}

// в”Җв”Җв”Җ Infrastructure Errors в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

export class NotFoundError extends AppError {
  readonly typeSlug = "not-found";
  readonly defaultTitle = "Resource Not Found";
  readonly httpStatus = 404;
}

export class ConflictError extends AppError {
  readonly typeSlug = "conflict";
  readonly defaultTitle = "Resource Conflict";
  readonly httpStatus = 409;
}
```

