## Part 3: Global Error Middleware

```typescript
// src/middleware/errorHandler.ts

import { Request, Response, NextFunction } from "express";
import { AppError, RateLimitError, ValidationError,
         AuthenticationRequiredError, InvalidTokenError } from "../errors/AppError";
import { logger } from "../lib/logger";

const ERROR_TYPE_BASE = "https://api.payments.example/errors";

/**
 * Builds an RFC 9457 Problem Details object.
 * https://www.rfc-editor.org/rfc/rfc9457
 */
function buildProblemDetails(
  err: AppError,
  req: Request
): Record<string, unknown> {
  const problem: Record<string, unknown> = {
    type:     `${ERROR_TYPE_BASE}/${err.typeSlug}`,
    title:    err.defaultTitle,
    status:   err.httpStatus,
    detail:   err.detail,
    instance: req.path,
  };

  // Merge extension fields (validation_errors, retry_after, etc.)
  // RFC 9457 В§3.1: extension members are permitted
  Object.assign(problem, err.extensions);

  // Always include trace_id for correlation вҖ” never include stack traces
  const traceId = (req as any).traceId ?? req.headers["x-request-id"];
  if (traceId) {
    problem.trace_id = traceId;
  }

  return problem;
}

/**
 * Sets HTTP headers required for specific error types.
 * Kept separate from body construction so each concern is explicit.
 */
function setErrorHeaders(err: AppError, res: Response): void {
  // в”Җв”Җ 401 errors MUST include WWW-Authenticate (RFC 9110 В§11.6.1) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  if (err instanceof AuthenticationRequiredError || err instanceof InvalidTokenError) {
    res.setHeader(
      "WWW-Authenticate",
      'Bearer realm="payments-api", error="invalid_token"'
    );
  }

  // в”Җв”Җ 429 errors MUST include Retry-After (contractual SLA obligation) в”Җв”Җв”Җв”Җв”Җв”Җ
  // This is enforced here вҖ” the only place responses are written вҖ”
  // so it cannot be accidentally omitted by individual route handlers.
  if (err instanceof RateLimitError) {
    res.setHeader("Retry-After",          String(err.retryAfterSeconds));
    res.setHeader("X-RateLimit-Limit",    String(err.limitMax));
    res.setHeader("X-RateLimit-Remaining","0");
    res.setHeader("X-RateLimit-Reset",    String(err.limitReset));
  }
}

/**
 * Determines log level by status code.
 * 5xx = error (paged), 4xx = warn (monitored), others = info.
 */
function logError(err: AppError | Error, req: Request): void {
  const status = err instanceof AppError ? err.httpStatus : 500;
  const meta = {
    path:    req.path,
    method:  req.method,
    status,
    traceId: (req as any).traceId,
    // Never log: request body, auth headers, card numbers
  };

  if (status >= 500) {
    logger.error({ err, ...meta }, "Server error");
  } else if (status >= 400) {
    logger.warn({ err: { message: err.message, type: err.name }, ...meta }, "Client error");
  }
}

/**
 * Global error handler вҖ” MUST be registered last in the Express middleware chain.
 *
 * Handles:
 *   1. Known AppError subclasses вҶ’ structured Problem Details
 *   2. Unknown/unexpected errors вҶ’ generic 500, no internal detail leaked
 *
 * This is the ONLY place in the codebase that writes error responses.
 */
export function globalErrorHandler(
  err: Error,
  req: Request,
  res: Response,
  _next: NextFunction   // 4-arg signature required by Express
): void {
  // в”Җв”Җ Guard: headers already sent (streaming response partially written) в”Җв”Җв”Җв”Җ
  if (res.headersSent) {
    logger.error({ err }, "Error after headers sent вҖ” cannot write Problem Details");
    return;
  }

  let appError: AppError;

  if (err instanceof AppError) {
    appError = err;
  } else {
    // Unknown error вҖ” do NOT leak internal details to the client.
    // Log the real error for debugging.
    logger.error({ err }, "Unhandled error вҖ” converting to generic 500");
    appError = new (class extends AppError {
      readonly typeSlug    = "internal-error";
      readonly defaultTitle = "Internal Server Error";
      readonly httpStatus  = 500;
    })("An unexpected error occurred. Please try again or contact support.");
  }

  logError(appError, req);
  setErrorHeaders(appError, res);

  const body = buildProblemDetails(appError, req);

  res
    .status(appError.httpStatus)
    .contentType("application/problem+json")  // ADR-003 requirement
    .json(body);
}

/**
 * 404 handler вҖ” registered before globalErrorHandler, after all routes.
 * Converts "no route matched" into a proper Problem Details response.
 */
export function notFoundHandler(req: Request, _res: Response, next: NextFunction): void {
  next(new NotFoundError(`No resource found at ${req.method} ${req.path}`));
}
```

