## Part 4: Authentication Error Distinction (401 vs 403)

This is a critical correctness issue. The distinction matters to clients:

| Scenario | Error Class | HTTP Status | Meaning |
|---|---|---|---|
| No `Authorization` header | `AuthenticationRequiredError` | **401** | "Who are you? Identify yourself." |
| Token present but malformed | `InvalidTokenError` | **401** | "I can't read this credential." |
| Token expired | `InvalidTokenError` | **401** | "Your credential has expired, re-authenticate." |
| Token signed with HS256 | `InvalidTokenError` | **401** | "Algorithm rejected (RS256 required)." |
| Token valid but wrong `aud` | `InvalidTokenError` | **401** | "This token is not for this service." |
| Token valid, but role/permission missing | `PermissionDeniedError` | **403** | "I know who you are. You can't do this." |
| Token valid, but wrong `tenant_id` for resource | `PermissionDeniedError` | **403** | "You don't own this resource." |

```typescript
// src/middleware/authenticate.ts

import { Request, Response, NextFunction } from "express";
import { jwtVerify, createRemoteJWKSet } from "jose";
import {
  AuthenticationRequiredError,
  InvalidTokenError,
  PermissionDeniedError,
} from "../errors/AppError";
import { config } from "../config";

const JWKS = createRemoteJWKSet(new URL(config.jwksUri));

export async function authenticate(
  req: Request,
  _res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const authHeader = req.headers.authorization;

    // в”Җв”Җ No credentials at all вҶ’ 401 в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    if (!authHeader || !authHeader.startsWith("Bearer ")) {
      return next(new AuthenticationRequiredError(
        "This endpoint requires a Bearer token in the Authorization header."
      ));
    }

    const token = authHeader.slice(7);

    let payload: any;
    try {
      const result = await jwtVerify(token, JWKS, {
        issuer:    "payments-auth",
        audience:  "payments-api",
        algorithms: ["RS256"],  // CRITICAL: RS256 only вҖ” SEC-2025-041
        // jose rejects any other algorithm, including HS256
      });
      payload = result.payload;
    } catch (joseError: any) {
      // в”Җв”Җ Invalid/expired/wrong-algorithm token вҶ’ 401 в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
      // Map jose error codes to human-readable detail
      const detail = mapJoseError(joseError);
      return next(new InvalidTokenError(detail));
    }

    // Token is cryptographically valid вҖ” attach identity to request
    (req as any).auth = {
      sub:        payload.sub,
      tenantId:   payload.tenant_id,
      roles:      payload.roles ?? [],
      permissions: payload.permissions ?? [],
    };

    next();
  } catch (unexpected) {
    next(unexpected);
  }
}

/**
 * Permission check middleware factory.
 * Call AFTER authenticate(). Throws 403 if permission is absent.
 *
 * Usage: router.post("/payments", authenticate, requirePermission("payments:create"), handler)
 */
export function requirePermission(permission: string) {
  return (req: Request, _res: Response, next: NextFunction): void => {
    const auth = (req as any).auth;

    // Defensive: authenticate() should have run first
    if (!auth) {
      return next(new AuthenticationRequiredError(
        "Authentication middleware did not run before permission check."
      ));
    }

    // в”Җв”Җ Authenticated but lacks permission вҶ’ 403 в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    if (!auth.permissions.includes(permission)) {
      return next(new PermissionDeniedError(
        `Your token does not include the '${permission}' permission required for this operation.`
      ));
    }

    next();
  };
}

function mapJoseError(err: any): string {
  switch (err.code) {
    case "ERR_JWT_EXPIRED":
      return "The provided token has expired. Please obtain a new token.";
    case "ERR_JWS_SIGNATURE_VERIFICATION_FAILED":
      return "Token signature verification failed. The token may have been tampered with.";
    case "ERR_JOSE_ALG_NOT_ALLOWED":
      // This fires when HS256 or any non-RS256 token is presented
      return "Token uses a disallowed signing algorithm. RS256 is required.";
    case "ERR_JWT_CLAIM_VALIDATION_FAILED":
      return "Token claim validation
